// Ensure telegram: prefix for sessionId when source is telegram
const item = $input.item;

if (item.json.source === 'telegram' && !item.json.sessionId.startsWith('telegram:')) {
  item.json.sessionId = 'telegram:' + item.json.sessionId;
}

// Ensure chat: prefix for chat sessions
if (item.json.source === 'chat' && !item.json.sessionId.startsWith('chat:')) {
  item.json.sessionId = 'chat:' + item.json.sessionId;
}

// Ensure webhook: prefix for webhook sessions
if (item.json.source === 'webhook' && !item.json.sessionId.startsWith('webhook:')) {
  item.json.sessionId = 'webhook:' + item.json.sessionId;
}

return item;

// Validate required fields and formats
const item = $input.item;
const errors = [];

// Validate sessionId format (must have channel prefix)
if (!item.json.sessionId) {
  errors.push('sessionId is required');
} else if (!/^(telegram|chat|webhook):/.test(item.json.sessionId)) {
  errors.push(`sessionId must start with telegram:, chat:, or webhook:. Got: ${item.json.sessionId}`);
}

// Validate traceId format (UUID or null)
if (item.json.traceId !== null && item.json.traceId !== undefined) {
  const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
  if (!uuidRegex.test(item.json.traceId)) {
    errors.push(`Invalid traceId format: ${item.json.traceId}. Must be UUID or null.`);
  }
}

// Validate source
const validSources = ['webhook', 'telegram', 'chat'];
if (!validSources.includes(item.json.source)) {
  errors.push(`Invalid source: ${item.json.source}. Must be one of: ${validSources.join(', ')}`);
}

// Validate message is not empty
if (!item.json.message || item.json.message.trim() === '') {
  errors.push('message cannot be empty');
}

if (errors.length > 0) {
  throw new Error(`Validation failed: ${errors.join('; ')}`);
}

return item;

